// ── Auth + validation payload ───────────────────────────────
// Si auth KO ou payload invalide → throw → output erreur (index 1) → Build Error Response
// Si tout OK → return payload → Trash Drive Folder

const SHARED_SECRET = 'TON_SECRET_ICI'; // à remplacer en prod

const body    = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

const provided =
  headers['x-siga-shared-secret'] ||
  (headers['authorization'] || '').replace(/^Bearer\s+/i, '');

if (provided !== SHARED_SECRET) {
  throw new Error(JSON.stringify({ ok: false, error: 'Unauthorized', code: 401 }));
}

const folder_id    = body.folder_id    || null;
const equipment_id = body.equipment_id || null;
const label        = body.label        || 'Équipement inconnu';

if (!folder_id) {
  throw new Error(JSON.stringify({ ok: false, error: 'folder_id manquant dans le payload', code: 400 }));
}

return [{ json: { ok: true, folder_id, equipment_id, label } }];

const payload = $('Validate Payload').item.json;
const now = new Date().toISOString();
console.log(`[SIGA_DELETE] ${now} — folder_id=${payload.folder_id} equipment_id=${payload.equipment_id} label="${payload.label}" → Drive folder deleted`);
return [{
  json: {
    ok: true,
    action: 'folder_deleted',
    folder_id: payload.folder_id,
    equipment_id: payload.equipment_id,
    label: payload.label,
    deleted_at: now
  }
}];

// Parse l'erreur lancée par Validate Payload ou Trash Drive Folder
// En mode continueErrorOutput, l'item d'erreur peut avoir différents formats
let body = { ok: false, error: 'Erreur inconnue', code: 500 };
try {
  const item = $input.first();
  // Format 1 : throw new Error(JSON.stringify({...})) depuis Code node
  const errMsg = (item.json && item.json.error)
    || (item.error && (item.error.message || item.error.description))
    || '';
  try {
    const parsed = JSON.parse(errMsg);
    if (parsed && (parsed.error || parsed.ok === false)) {
      body = parsed;
    } else {
      body.error = errMsg || 'Erreur interne';
    }
  } catch (_) {
    body.error = errMsg || 'Erreur interne';
  }
} catch (e) {
  body.error = 'Erreur interne';
}
return [{ json: body }];
